   294вҶ’</head>
   295вҶ’<body>
   296вҶ’    <div class="game-container">
   297вҶ’        <div class="game-header">
   298вҶ’            <h1>вҷҡ Xadrez FГЎcil вҷӣ</h1>
   299вҶ’        </div>
   300вҶ’
   301вҶ’        <div class="game-info">
   302вҶ’            <div class="turn-indicator" id="turnIndicator">Vez das Brancas</div>
   303вҶ’            <div class="status-message" id="statusMessage"></div>
   304вҶ’        </div>
   305вҶ’
   306вҶ’        <div class="captured-pieces">
   307вҶ’            <div class="captured-side" id="capturedWhite"></div>
   308вҶ’            <div class="captured-side" id="capturedBlack"></div>
   309вҶ’        </div>
   310вҶ’
   311вҶ’        <div class="chess-board" id="chessBoard"></div>
   312вҶ’
   313вҶ’        <div class="controls">
   314вҶ’            <button class="btn btn-primary" onclick="resetGame()">Novo Jogo</button>
   315вҶ’            <button class="btn btn-secondary" onclick="undoMove()">Desfazer</button>
   316вҶ’        </div>
   317вҶ’
   318вҶ’        <div class="move-history">
   319вҶ’            <h3>HistГіrico de Jogadas</h3>
   320вҶ’            <div class="moves-list" id="movesList"></div>
   321вҶ’        </div>
   322вҶ’    </div>
   323вҶ’
   324вҶ’    <script>
   325вҶ’        // Chess pieces Unicode
   326вҶ’        const PIECES = {
   327вҶ’            white: { king: 'вҷ”', queen: 'вҷ•', rook: 'вҷ–', bishop: 'вҷ—', knight: 'вҷҳ', pawn: 'вҷҷ' },
   328вҶ’            black: { king: 'вҷҡ', queen: 'вҷӣ', rook: 'вҷң', bishop: 'вҷқ', knight: 'вҷһ', pawn: 'вҷҹ' }
   329вҶ’        };
   330вҶ’
   331вҶ’        // Initial board setup
   332вҶ’        const INITIAL_BOARD = [
   333вҶ’            ['r', 'n', 'b', 'q', 'k', 'b', 'n', 'r'],
   334вҶ’            ['p', 'p', 'p', 'p', 'p', 'p', 'p', 'p'],
   335вҶ’            ['', '', '', '', '', '', '', ''],
   336вҶ’            ['', '', '', '', '', '', '', ''],
   337вҶ’            ['', '', '', '', '', '', '', ''],
   338вҶ’            ['', '', '', '', '', '', '', ''],
   339вҶ’            ['P', 'P', 'P', 'P', 'P', 'P', 'P', 'P'],
   340вҶ’            ['R', 'N', 'B', 'Q', 'K', 'B', 'N', 'R']
   341вҶ’        ];
   342вҶ’
   343вҶ’        let board = [];
   344вҶ’        let selectedSquare = null;
   345вҶ’        let currentTurn = 'white';
   346вҶ’        let moveHistory = [];
   347вҶ’        let capturedPieces = { white: [], black: [] };
   348вҶ’        let lastMove = null;
   349вҶ’        let castlingRights = {
   350вҶ’            white: { kingSide: true, queenSide: true },
   351вҶ’            black: { kingSide: true, queenSide: true }
   352вҶ’        };
   353вҶ’        let enPassantTarget = null;
   354вҶ’
   355вҶ’        function initGame() {
   356вҶ’            board = JSON.parse(JSON.stringify(INITIAL_BOARD));
   357вҶ’            selectedSquare = null;
   358вҶ’            currentTurn = 'white';
   359вҶ’            moveHistory = [];
   360вҶ’            capturedPieces = { white: [], black: [] };
   361вҶ’            lastMove = null;
   362вҶ’            castlingRights = {
   363вҶ’                white: { kingSide: true, queenSide: true },
   364вҶ’                black: { kingSide: true, queenSide: true }
   365вҶ’            };
   366вҶ’            enPassantTarget = null;
   367вҶ’            renderBoard();
   368вҶ’            updateGameInfo();
   369вҶ’        }
   370вҶ’
   371вҶ’        function renderBoard() {
   372вҶ’            const boardElement = document.getElementById('chessBoard');
   373вҶ’            boardElement.innerHTML = '';
   374вҶ’
   375вҶ’            for (let row = 0; row < 8; row++) {
   376вҶ’                for (let col = 0; col < 8; col++) {
   377вҶ’                    const square = document.createElement('div');
   378вҶ’                    const isLight = (row + col) % 2 === 0;
   379вҶ’                    square.className = `square ${isLight ? 'light' : 'dark'}`;
   380вҶ’                    square.dataset.row = row;
   381вҶ’                    square.dataset.col = col;
   382вҶ’
   383вҶ’                    const piece = board[row][col];
   384вҶ’                    if (piece) {
   385вҶ’                        const pieceColor = piece === piece.toUpperCase() ? 'white' : 'black';
   386вҶ’                        const pieceType = getPieceType(piece);
   387вҶ’                        const pieceElement = document.createElement('span');
   388вҶ’                        pieceElement.className = `piece ${pieceColor}`;
   389вҶ’                        pieceElement.textContent = PIECES[pieceColor][pieceType];
   390вҶ’                        square.appendChild(pieceElement);
   391вҶ’                    }
   392вҶ’
   393вҶ’                    // Highlight last move
   394вҶ’                    if (lastMove && ((lastMove.from.row === row && lastMove.from.col === col) ||
   395вҶ’                        (lastMove.to.row === row && lastMove.to.col === col))) {
   396вҶ’                        square.classList.add('last-move');
   397вҶ’                    }
   398вҶ’
   399вҶ’                    // Highlight selected square
   400вҶ’                    if (selectedSquare && selectedSquare.row === row && selectedSquare.col === col) {
   401вҶ’                        square.classList.add('selected');
   402вҶ’                    }
   403вҶ’
   404вҶ’                    // Highlight valid moves
   405вҶ’                    if (selectedSquare) {
   406вҶ’                        const moves = getValidMoves(selectedSquare.row, selectedSquare.col);
   407вҶ’                        if (moves.some(m => m.row === row && m.col === col)) {
   408вҶ’                            if (piece) {
   409вҶ’                                square.classList.add('capture-move');
   410вҶ’                            } else {
   411вҶ’                                square.classList.add('valid-move');
   412вҶ’                            }
   413вҶ’                        }
   414вҶ’                    }
   415вҶ’
   416вҶ’                    // Highlight king in check
   417вҶ’                    if (piece && piece.toLowerCase() === 'k') {
   418вҶ’                        const pieceColor = piece === piece.toUpperCase() ? 'white' : 'black';
   419вҶ’                        if (isInCheck(pieceColor)) {
   420вҶ’                            square.classList.add('in-check');
   421вҶ’                        }
   422вҶ’                    }
   423вҶ’
   424вҶ’                    square.addEventListener('click', () => handleSquareClick(row, col));
   425вҶ’                    boardElement.appendChild(square);
   426вҶ’                }
   427вҶ’            }
   428вҶ’        }
   429вҶ’
   430вҶ’        function getPieceType(piece) {
   431вҶ’            const pieceLower = piece.toLowerCase();
   432вҶ’            const types = {
   433вҶ’                'k': 'king', 'q': 'queen', 'r': 'rook',
   434вҶ’                'b': 'bishop', 'n': 'knight', 'p': 'pawn'
   435вҶ’            };
   436вҶ’            return types[pieceLower];
   437вҶ’        }
   438вҶ’
   439вҶ’        function handleSquareClick(row, col) {
   440вҶ’            const piece = board[row][col];
   441вҶ’            const pieceColor = piece ? (piece === piece.toUpperCase() ? 'white' : 'black') : null;
   442вҶ’
   443вҶ’            if (selectedSquare) {
   444вҶ’                const moves = getValidMoves(selectedSquare.row, selectedSquare.col);
   445вҶ’                const validMove = moves.find(m => m.row === row && m.col === col);
   446вҶ’
   447вҶ’                if (validMove) {
   448вҶ’                    makeMove(selectedSquare.row, selectedSquare.col, row, col);
   449вҶ’                    selectedSquare = null;
   450вҶ’                } else if (pieceColor === currentTurn) {
   451вҶ’                    selectedSquare = { row, col };
   452вҶ’                } else {
   453вҶ’                    selectedSquare = null;
   454вҶ’                }
   455вҶ’            } else if (pieceColor === currentTurn) {
   456вҶ’                selectedSquare = { row, col };
   457вҶ’            }
   458вҶ’
   459вҶ’            renderBoard();
   460вҶ’        }
   461вҶ’
   462вҶ’        function makeMove(fromRow, fromCol, toRow, toCol) {
   463вҶ’            const piece = board[fromRow][fromCol];
   464вҶ’            const capturedPiece = board[toRow][toCol];
   465вҶ’            const pieceColor = piece === piece.toUpperCase() ? 'white' : 'black';
   466вҶ’
   467вҶ’            // Save move for history
   468вҶ’            const move = {
   469вҶ’                from: { row: fromRow, col: fromCol },
   470вҶ’                to: { row: toRow, col: toCol },
   471вҶ’                piece: piece,
   472вҶ’                captured: capturedPiece,
   473вҶ’                castling: null,
   474вҶ’                enPassant: false,
   475вҶ’                promotion: false
   476вҶ’            };
   477вҶ’
   478вҶ’            // Handle en passant capture
   479вҶ’            if (piece.toLowerCase() === 'p' && enPassantTarget &&
   480вҶ’                toRow === enPassantTarget.row && toCol === enPassantTarget.col) {
   481вҶ’                const capturedPawnRow = pieceColor === 'white' ? toRow + 1 : toRow - 1;
   482вҶ’                const capturedPawn = board[capturedPawnRow][toCol];
   483вҶ’                capturedPieces[pieceColor].push(capturedPawn);
   484вҶ’                board[capturedPawnRow][toCol] = '';
   485вҶ’                move.enPassant = true;
   486вҶ’                move.captured = capturedPawn;
   487вҶ’            }
   488вҶ’
   489вҶ’            // Handle castling
   490вҶ’            if (piece.toLowerCase() === 'k' && Math.abs(fromCol - toCol) === 2) {
   491вҶ’                const isKingSide = toCol > fromCol;
   492вҶ’                const rookFromCol = isKingSide ? 7 : 0;
   493вҶ’                const rookToCol = isKingSide ? 5 : 3;
   494вҶ’                board[toRow][rookToCol] = board[toRow][rookFromCol];
   495вҶ’                board[toRow][rookFromCol] = '';
   496вҶ’                move.castling = isKingSide ? 'kingSide' : 'queenSide';
   497вҶ’            }
   498вҶ’
   499вҶ’            // Update castling rights
   500вҶ’            if (piece.toLowerCase() === 'k') {
   501вҶ’                castlingRights[pieceColor].kingSide = false;
   502вҶ’                castlingRights[pieceColor].queenSide = false;
   503вҶ’            }
   504вҶ’            if (piece.toLowerCase() === 'r') {
   505вҶ’                if (fromCol === 0) castlingRights[pieceColor].queenSide = false;
   506вҶ’                if (fromCol === 7) castlingRights[pieceColor].kingSide = false;
   507вҶ’            }
   508вҶ’
   509вҶ’            // Set en passant target
   510вҶ’            enPassantTarget = null;
   511вҶ’            if (piece.toLowerCase() === 'p' && Math.abs(fromRow - toRow) === 2) {
   512вҶ’                enPassantTarget = {
   513вҶ’                    row: (fromRow + toRow) / 2,
   514вҶ’                    col: fromCol
   515вҶ’                };
